from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Initialize LeannSearcher to get the PassageManager and check for metadata file existence
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found: {e}")

    total_passages = searcher.passage_manager.get_passage_count()

    # Read the metadata file to get passage_sources
    meta_path = f"{index_path}.meta.json"
    with open(meta_path, 'r') as f:
        meta_data = json.load(f)

    passage_sources = meta_data.get('passage_sources', [])

    # Collect all metadata from all passages
    all_metadata = []

    for source in passage_sources:
        source_path = source.get('path', '')
        jsonl_file = Path(meta_path).parent / source_path

        if not jsonl_file.exists():
            continue  # Skip if file doesn't exist

        with open(jsonl_file, 'r') as f:
            for line in f:
                if not line.strip():  # Skip empty lines
                    continue
                try:
                    data = json.loads(line)
                    if 'metadata' in data:
                        all_metadata.append(data['metadata'])
                except json.JSONDecodeError:
                    continue  # Skip invalid lines

    # Process all metadata to get the required stats
    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for metadata in all_metadata:
        for field, value in metadata.items():
            metadata_fields.add(field)
            # Count the value for each field
            field_value_counts[field][value] += 1

    # Convert to the required format
    result = {
        "total_passages": total_passages,
        "metadata_fields": list(metadata_fields),
        "field_value_counts": {field: dict(counts) for field, counts in field_value_counts.items()}
    }

    return result

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    # Check if required_fields is empty
    if not required_fields:
        return {
            "coverage_percentage": 100.0,
            "field_coverage": {},
            "missing_fields": []
        }

    # Initialize LeannSearcher to check for metadata file existence
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found: {e}")

    total_passages = searcher.passage_manager.get_passage_count()

    if total_passages == 0:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": list(required_fields)
        }

    meta_path = f"{index_path}.meta.json"
    with open(meta_path, 'r') as f:
        meta_data = json.load(f)

    passage_sources = meta_data.get('passage_sources', [])

    # Collect all metadata from all passages
    all_metadata = []

    for source in passage_sources:
        source_path = source.get('path', '')
        jsonl_file = Path(meta_path).parent / source_path

        if not jsonl_file.exists():
            continue

        with open(jsonl_file, 'r') as f:
            for line in f:
                if not line.strip():
                    continue
                try:
                    data = json.loads(line)
                    if 'metadata' in data:
                        all_metadata.append(data['metadata'])
                except json.JSONDecodeError:
                    continue

    # Analyze coverage
    full_coverage_count = 0
    field_coverage = {field: 0 for field in required_fields}
    missing_fields = set(required_fields)

    for metadata in all_metadata:
        present_fields = set()
        for field in required_fields:
            if field in metadata:
                present_fields.add(field)
                field_coverage[field] += 1

        # Check if all required fields are present
        if present_fields == set(required_fields):
            full_coverage_count += 1
        else:
            # Update missing_fields: fields not present in this passage
            for field in required_fields:
                if field not in present_fields:
                    missing_fields.add(field)

    # Calculate percentages
    coverage_percentage = (full_coverage_count / total_passages) * 100.0
    field_coverage_percentages = {field: (count / total_passages) * 100.0 
                                 for field, count in field_coverage.items()}

    # Determine missing fields (fields not present in any passage)
    missing_fields = [field for field in required_fields 
                     if field not in field_coverage_percentages or field_coverage_percentages[field] == 0.0]

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": field_coverage_percentages,
        "missing_fields": missing_fields
    }
